// ── Lookup helper ────────────────────────────────────────────────────────────
function getUniversityIntel(name) {
  return UNIVERSITY_INTELLIGENCE[name] || null;
}

// ── Major cluster extraction ─────────────────────────────────────────────────
// Derives 2-3 major strength tags from pipeline field for each school
function getMajorStrengths(name) {
  const intel = getUniversityIntel(name);
  if (!intel || !intel.pipeline) return [];
  const p = intel.pipeline.toLowerCase();
  const strengths = [];
  if (/engineering|aerospace|mechanical|electrical|civil|chemical|biomedical/.test(p)) strengths.push('Engineering');
  if (/computer science|software|cs|computing|informatics|artificial intelligence|machine learning/.test(p)) strengths.push('Computer Science');
  if (/business|mba|finance|accounting|marketing|management|supply chain/.test(p)) strengths.push('Business');
  if (/medicine|medical|health|nursing|pharmacy|pre-med|clinical|healthcare/.test(p)) strengths.push('Health Sciences');
  if (/law|legal|pre-law|political science|policy|government/.test(p)) strengths.push('Law & Policy');
  if (/film|media|journalism|communication|entertainment|tv|television/.test(p)) strengths.push('Media & Communications');
  if (/art|design|architecture|creative|studio/.test(p)) strengths.push('Arts & Design');
  if (/science|biology|chemistry|physics|research|stem/.test(p)) strengths.push('Sciences');
  if (/education|teaching|pedagogy|school of education/.test(p)) strengths.push('Education');
  if (/entrepreneurship|startup|venture|innovation/.test(p)) strengths.push('Entrepreneurship');
  if (/energy|petroleum|oil|gas|environmental/.test(p)) strengths.push('Energy & Environment');
  if (/music|performing arts|theatre|dance/.test(p)) strengths.push('Performing Arts');
  return [...new Set(strengths)].slice(0, 4);
}

// ── Graduate city parser ─────────────────────────────────────────────────────
// Returns top 3 cities with percentages from grad_cities field
function getTopGradCities(name) {
  const intel = getUniversityIntel(name);
  if (!intel || !intel.grad_cities) return [];
  const matches = intel.grad_cities.match(/([A-Za-z\s\-]+(?:DC|CA|NY|TX|IL|MA|FL|GA|WA|CO|OH|PA|NC|VA|MI|MN|MO|TN|AZ|NV|OR|UT|CT|IN|WI|MD|NJ|SC|KY|LA|OK|KS|AR|MS|AL|IA|NE|ID|ME|VT|NH|WV|DE|RI|MT|SD|ND|WY|AK|HI))\s*\((\d+)%\)/g) || [];
  return matches.slice(0, 3).map(m => {
    const parts = m.match(/(.+?)\s*\((\d+)%\)/);
    return parts ? { city: parts[1].trim(), pct: parseInt(parts[2]) } : null;
  }).filter(Boolean);
}